from django.utils.text import slugify


def _unique_slug(base_slug, existing_slugs):
    if base_slug not in existing_slugs:
        return base_slug
    idx = 1
    while f"{base_slug}-{idx}" in existing_slugs:
        idx += 1
    return f"{base_slug}-{idx}"


