    existing_slugs = set(
        Organizacion.objects.exclude(slug__isnull=True).exclude(slug="").values_list("slug", flat=True)
    )

    for org in Organization.objects.all():
        base_slug = org.slug or slugify(org.name or "org")
        slug = _unique_slug(base_slug, existing_slugs)
        existing_slugs.add(slug)

        codigo = (slug or (org.name or "ORG")).upper()[:50]

        existing = (
            Organizacion.objects.filter(slug__iexact=slug).first()
            or Organizacion.objects.filter(codigo__iexact=codigo).first()
            or Organizacion.objects.filter(nombre__iexact=org.name).first()
        )

        data = {
            "nombre": org.name,
            "codigo": codigo,
            "slug": slug,
            "razon_social": org.display_name or "",
            "email": org.email or "",
            "telefono": org.phone or "",
            "website": org.website or "",
            "direccion": org.address or "",
            "city": org.city or "",
            "state": org.state or "",
            "country": org.country or "",
            "postal_code": org.postal_code or "",
            "activa": org.is_active,
            "plan": org.plan,
            "max_users": org.max_users,
            "max_storage_mb": org.max_storage_mb,
            "is_trial": org.is_trial,
            "trial_ends_at": org.trial_ends_at,
            "primary_color": org.primary_color or "#007bff",
            "settings": org.settings or {},
        }

        if existing:
            for key, value in data.items():
                current = getattr(existing, key, None)
                if current in [None, "", {}, []]:
                    setattr(existing, key, value)
            # Guardar descripción en metadata si existe
            if org.description:
                existing.metadata = existing.metadata or {}
                existing.metadata.setdefault("description", org.description)
            if org.display_name:
                existing.metadata = existing.metadata or {}
                existing.metadata.setdefault("display_name", org.display_name)
            existing.save()
        else:
            metadata = {}
            if org.description:
                metadata["description"] = org.description
            if org.display_name:
                metadata["display_name"] = org.display_name
            Organizacion.objects.create(
                **data,
                metadata=metadata
            )


